        using (var store = Seeded())
        using (var draft = store.Checkout(null))
        {
            draft.TrySetEmail(fixture.SecondaryTheirs);
            stash = draft.Stash();
        }
        var tightened = stash with { Email = stash.Email with { Base = fixture.SecondaryInvalid } }; // ancestor no longer parses
        using var store2 = Seeded(); // canonical secondary == secondaryBase, differs from the rescued value
        using var restored = store2.Restore(store2.AcceptStash(tightened), null);
        var snap = restored.Snapshot();
        Assert.That(snap.Email.Dirty, Is.True, "the rescued value survives, dirty");
        Assert.That(snap.Email.Sync, Is.InstanceOf<TextFieldSync.Conflicted>(), "a lost ancestor conflicts, it does not overwrite (C03)");
        var sync = (TextFieldSync.Conflicted)snap.Email.Sync;
        Assert.That(sync.Theirs, Is.EqualTo(fixture.SecondaryBase));
        Assert.That(sync.Base, Is.Null, "no ancestor is fabricated");
    }

    /// C23 — ...and the convergence guard: a lost ancestor whose rescued value equals canonical lands clean (C04).
    [Test]
    public void C23_ADegradedAncestorConvergesClean()
    {
        ProfileStashFfi stash;
        using (var store = Seeded())
        using (var draft = store.Checkout(null))
        {
            draft.TrySetEmail(fixture.SecondaryTheirs);
            stash = draft.Stash();
        }
        var tightened = stash with { Email = stash.Email with { Base = fixture.SecondaryInvalid } };
        using var store2 = new ProfileStoreFfi();
        store2.ApplyCanonical(fixture.Seed() with { Email = fixture.SecondaryTheirs }); // canonical == the rescued value
        using var restored = store2.Restore(store2.AcceptStash(tightened), null);
        var snap = restored.Snapshot();
        Assert.That(snap.Email.Sync, Is.EqualTo(new TextFieldSync.InSync()), "a lost ancestor that converges lands clean");
        Assert.That(snap.Email.Dirty, Is.False);
    }

    /// C13 — a value-moving edit resets the async verdict; a verdict endorses a value, so a changed value un-endorses it.
    [Test]
    public void C13_AValueMovingEditResetsTheVerdict()
    {
        using var store = Seeded();
        using var draft = store.Checkout(new PassingChecker());
        draft.TrySetUsername(fixture.CheckedMine);
        Assert.That(draft.RunUsernameCheck(), Is.True, "a check ran (the bool is 'ran', not the verdict)");
        Assert.That(draft.Snapshot().UsernameCheck, Is.EqualTo(new CheckStateFfi.Passed()));
        draft.TrySetUsername(fixture.CheckedTheirs); // a different value
        Assert.That(draft.Snapshot().UsernameCheck, Is.EqualTo(new CheckStateFfi.Unchecked()), "a changed value un-endorses");
    }

    /// C13 — a value-preserving edit (edit-to-same) leaves the verdict standing.
    [Test]
    public void C13_AValuePreservingEditLeavesTheVerdictStanding()
    {
        using var store = Seeded();
        using var draft = store.Checkout(new PassingChecker());
        draft.TrySetUsername(fixture.CheckedMine);
        Assert.That(draft.RunUsernameCheck(), Is.True);
        draft.TrySetUsername(fixture.CheckedMine); // edit to the SAME value
        Assert.That(draft.Snapshot().UsernameCheck, Is.EqualTo(new CheckStateFfi.Passed()), "value-based, like dirty");
    }

    /// C13 — a preserved conflict leaves the verdict standing; resolving take-theirs moves the value and resets it.
    [Test]
    public void C13_TakeTheirsMovesTheValueAndResetsTheVerdict()
    {
        using var store = Seeded();
        using var draft = store.Checkout(new PassingChecker());
        draft.TrySetUsername(fixture.CheckedMine);
        Assert.That(draft.RunUsernameCheck(), Is.True);
        store.ApplyCanonical(fixture.Seed() with { Username = fixture.CheckedTheirs }); // conflicts; value stays mine
        Assert.That(draft.Snapshot().UsernameCheck, Is.EqualTo(new CheckStateFfi.Passed()), "a conflict that preserves your value leaves the verdict standing");
        draft.ResolveTakeTheirs(ProfileFieldId.Username); // value moves to theirs
        Assert.That(draft.Snapshot().UsernameCheck, Is.EqualTo(new CheckStateFfi.Unchecked()));
    }

    /// C16 — an unrun check on a dirty checked field blocks submit, pinned and keyed; a passing check
    /// unblocks it. The capability was present from checkout (D34) — C16 binds on UNRUN, not on absent.
    [Test]
    public void C16_AnUnrunCheckOnADirtyCheckedFieldBlocksSubmit()
    {
        using var store = Seeded();
        using var draft = store.Checkout(new PassingChecker());
        draft.TrySetUsername(fixture.CheckedMine);
        Assert.That(draft.Snapshot().UsernameCheck, Is.EqualTo(new CheckStateFfi.Unchecked()));
        var ex = Assert.Throws<SubmitErrorFfiException>(() => draft.Submit());
        Assert.That(ex!.Error, Is.InstanceOf<SubmitErrorFfi.Validation>(), "an unchecked dirty checked field must not commit");
        var report = ((SubmitErrorFfi.Validation)ex.Error).Report;
        var violation = report.RuleErrors.First(v => v.Rule == "username_unique");
        Assert.That(violation.Error.Key, Is.EqualTo("username_check_required"));
        Assert.That(violation.Pins, Is.EqualTo(new[] { ProfileFieldId.Username }));
        Assert.That(draft.RunUsernameCheck(), Is.True);
        draft.Submit(); // now unblocked
    }

    /// C16 — the other half: a clean checked field needs no check, or an edit to another field could never submit.
    [Test]
    public void C16_ACleanCheckedFieldNeedsNoCheck()
    {
        using var store = Seeded();
        using var draft = store.Checkout(null);
        draft.TrySetName(fixture.PrimaryMine); // edit a NON-checked field
        Assert.That(draft.Snapshot().Username.Dirty, Is.False);
        Assert.DoesNotThrow(() => draft.Submit()); // must not throw
    }

